define i23 @test11(i23 %x) {
  %a = mul i23 %x, 3
  %b = lshr i23 %a, 11
  %c = shl i23 %b, 12
  ret i23 %c
}

define i47 @test12(i47 %X) {
  %sh1 = ashr i47 %X, 8
  %sh2 = shl i47 %sh1, 8
  ret i47 %sh2
}

define <2 x i47> @test12_splat_vec(<2 x i47> %X) {
  %sh1 = ashr <2 x i47> %X, <i47 8, i47 8>
  %sh2 = shl <2 x i47> %sh1, <i47 8, i47 8>
  ret <2 x i47> %sh2
}

define i40 @test26(i40 %A) {
  %B = lshr i40 %A, 1
  %C = bitcast i40 %B to i40
  %D = shl i40 %C, 1
  ret i40 %D
}

define i8 @fold_add_zext_eq_0(i8 %x) {
  %x_eq = icmp eq i8 %x, 0
  %x_eq_ext = zext i1 %x_eq to i8
  %r = add i8 %x, %x_eq_ext
  ret i8 %r
}
